  .badge-active { background: rgba(118,163,121,0.15); color: var(--sage); border: 1px solid rgba(118,163,121,0.25); }
  .badge-pending { background: rgba(210,169,116,0.15); color: #9a7030; border: 1px solid rgba(210,169,116,0.25); }
  .badge-critical { background: rgba(184,135,148,0.15); color: var(--pink); border: 1px solid rgba(184,135,148,0.25); }
  .card-mi { background: var(--white); border-radius: 10px; border: 1px solid var(--cream2); padding: 1.5rem; margin-bottom: 0.75rem; }
  .card-mi-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 0.75rem; }
  .card-mi-title { font-weight: 600; font-size: 0.9rem; color: var(--forest); }
  .card-mi-body { font-size: 0.82rem; color: var(--sage2); line-height: 1.65; }
  .progress-mi { height: 5px; background: var(--cream2); border-radius: 10px; overflow: hidden; margin-top: 1rem; }
  .progress-mi-fill { height: 100%; border-radius: 10px; background: linear-gradient(90deg, var(--sage), var(--mint)); }

  /* ── QUICK REFERENCE ── */
  .quick-ref-table { width: 100%; border-collapse: collapse; background: var(--white); border-radius: 10px; overflow: hidden; border: 1px solid var(--cream2); }
  .quick-ref-table thead th { background: var(--forest); color: rgba(238,240,236,0.72); font-family: 'DM Mono', monospace; font-size: 0.63rem; letter-spacing: 3px; text-transform: uppercase; padding: 0.9rem 1.25rem; font-weight: 400; text-align: left; }
  .quick-ref-table tbody td { padding: 0.85rem 1.25rem; font-size: 0.84rem; color: var(--forest); border-bottom: 1px solid var(--cream2); vertical-align: middle; }
  .quick-ref-table tbody tr:last-child td { border-bottom: none; }
  .quick-ref-table tbody tr:hover td { background: rgba(238,240,236,0.6); }

  /* ── BRAND STORY ── */
  .story-split {
    display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2.5rem;
  }
  .story-block {
    background: var(--forest); border-radius: 12px; padding: 3rem; position: relative; overflow: hidden;
  }
  .story-block::before {
    content: ''; position: absolute; bottom: -40px; right: -40px;
    width: 160px; height: 160px;
    background: radial-gradient(circle, rgba(210,169,116,0.1) 0%, transparent 65%);
    border-radius: 50%;
  }
  .story-block-light { background: var(--cream2); border: 1px solid var(--cream2); }
  .story-number {
    font-family: 'Bebas Neue', sans-serif; font-size: 5rem;
    color: rgba(118,163,121,0.12); line-height: 1; position: absolute; top: 1.5rem; right: 2rem;
    pointer-events: none;
  }
  .story-block-eyebrow {
    font-family: 'DM Mono', monospace; font-size: 0.62rem; letter-spacing: 4px;
    text-transform: uppercase; color: var(--gold); margin-bottom: 1rem;
  }
  .story-block-light .story-block-eyebrow { color: var(--sage2); }
  .story-block-headline {
    font-family: 'Bebas Neue', sans-serif; font-size: 1.85rem; letter-spacing: 0.5px;
    color: var(--cream); line-height: 1.05; margin-bottom: 1rem; position: relative; z-index: 1;
  }
  .story-block-light .story-block-headline { color: var(--forest); }
  .story-block-body { font-size: 0.875rem; color: rgba(238,240,236,0.62); line-height: 1.75; position: relative; z-index: 1; }
  .story-block-light .story-block-body { color: var(--sage2); }
  .promise-strip {
    background: linear-gradient(135deg, var(--forest) 0%, #2d4a3e 100%);
    border-radius: 12px; padding: 3rem 4rem; margin-bottom: 2.5rem;
    border-left: 4px solid var(--gold); position: relative; overflow: hidden;
  }
  .promise-strip::after {
    content: '"'; font-family: 'Bebas Neue', sans-serif; font-size: 18rem;
    color: rgba(118,163,121,0.05); position: absolute; right: 3rem; top: -4rem; line-height: 1;
    pointer-events: none;
  }
  .values-grid {
    display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; margin-bottom: 2rem;
  }
  .value-card {
    background: var(--white); border-radius: 10px; border: 1px solid var(--cream2);
    padding: 2rem; transition: transform 0.2s, box-shadow 0.2s;
  }
  .value-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(37,56,48,0.08); }
  .value-number {
    font-family: 'DM Mono', monospace; font-size: 0.58rem; letter-spacing: 3px;
    text-transform: uppercase; color: var(--gold); margin-bottom: 0.75rem;
  }
  .value-title {
    font-family: 'Bebas Neue', sans-serif; font-size: 1.35rem; letter-spacing: 0.5px;
    color: var(--forest); margin-bottom: 0.5rem;
  }
  .value-body { font-size: 0.825rem; color: var(--sage2); line-height: 1.68; }
  .value-icon {
    width: 38px; height: 38px; border-radius: 8px; background: var(--cream);
    display: flex; align-items: center; justify-content: center;
    font-size: 1rem; color: var(--sage); margin-bottom: 1.25rem;
  }

  /* ── BRAND VOICE ── */
  .voice-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem; }
  .voice-card {
    border-radius: 10px; border: 1px solid var(--cream2); padding: 2rem;
    background: var(--white); transition: transform 0.2s, box-shadow 0.2s;
  }
  .voice-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(37,56,48,0.08); }
  .voice-card-label {
    font-family: 'DM Mono', monospace; font-size: 0.6rem; letter-spacing: 3px;
    text-transform: uppercase; color: var(--sage2); margin-bottom: 0.5rem;
  }
  .voice-card-title {
    font-family: 'Bebas Neue', sans-serif; font-size: 1.55rem; letter-spacing: 0.5px;
    color: var(--forest); margin-bottom: 0.75rem;
  }
  .voice-card-body { font-size: 0.855rem; color: var(--sage2); line-height: 1.72; }
  .voice-do { border-left: 3px solid rgba(118,163,121,0.5); }
  .voice-dont { border-left: 3px solid rgba(184,135,148,0.5); }
  .tone-spectrum {
    background: var(--forest); border-radius: 12px; padding: 3rem; margin-bottom: 2rem;
  }
  .tone-axis {
    display: flex; justify-content: space-between; align-items: center; margin-bottom: 0.75rem;
  }
  .tone-bar {
    flex: 1; height: 4px; margin: 0 1rem; border-radius: 2px;
    background: linear-gradient(90deg, var(--sage) 0%, var(--gold) 100%);
  }
  .tone-label {
    font-family: 'DM Mono', monospace; font-size: 0.6rem; letter-spacing: 2px;
    text-transform: uppercase; color: var(--mint);
  }
  .tone-marker {
    width: 10px; height: 10px; border-radius: 50%; background: var(--gold);
    border: 2px solid var(--forest); position: relative;
  }

  /* ── LOGO CLEARSPACE ── */
  .clearspace-demo {
    background: var(--cream); border: 1px solid var(--cream2); border-radius: 12px;
    padding: 4rem; display: flex; align-items: center; justify-content: center;
    position: relative; margin-bottom: 2rem; overflow: hidden;
  }
  .clearspace-inner {
    position: relative; display: inline-block;
  }
  .clearspace-box {
    position: absolute; inset: -32px;
    border: 1.5px dashed rgba(118,163,121,0.5);
    border-radius: 4px; pointer-events: none;
  }
  .clearspace-label {
    position: absolute; font-family: 'DM Mono', monospace; font-size: 0.55rem;
    letter-spacing: 2px; text-transform: uppercase; color: var(--sage);
    white-space: nowrap;
  }
  .sizing-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; margin-bottom: 2rem; }
  .sizing-card {
    background: var(--white); border-radius: 10px; border: 1px solid var(--cream2);
    padding: 1.5rem; text-align: center;
  }
  .sizing-preview {
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 1rem; height: 60px;
  }
  .sizing-label { font-family: 'DM Mono', monospace; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; color: var(--sage2); margin-bottom: 2px; }
  .sizing-use { font-size: 0.78rem; color: var(--forest); font-weight: 500; }

  /* ── TYPE RULES ── */
  .type-rules-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem; }
  .type-rule-card {
    background: var(--white); border-radius: 10px; border: 1px solid var(--cream2);
    padding: 2rem; transition: box-shadow 0.2s;
  }
  .type-rule-card:hover { box-shadow: 0 8px 24px rgba(37,56,48,0.08); }
  .type-rule-label {
    font-family: 'DM Mono', monospace; font-size: 0.6rem; letter-spacing: 3px;
    text-transform: uppercase; color: var(--gold); margin-bottom: 0.75rem;
    padding-bottom: 0.75rem; border-bottom: 1px solid var(--cream2);
  }
  .type-do-dont {
    display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem;
  }
  .type-do-card {
    border-radius: 10px; border: 1px solid rgba(118,163,121,0.3);
    background: var(--white); padding: 2rem; overflow: hidden;
  }
  .type-dont-card {
    border-radius: 10px; border: 1px solid rgba(184,135,148,0.3);
    background: var(--white); padding: 2rem; overflow: hidden;
  }
  .type-sample-do { color: var(--forest); }
  .type-sample-dont { opacity: 0.65; }
  .type-verdict {
    font-family: 'DM Mono', monospace; font-size: 0.6rem; letter-spacing: 2px;
    text-transform: uppercase; margin-bottom: 0.75rem; padding: 3px 10px; border-radius: 20px;
    display: inline-block;
  }
  .verdict-do { background: rgba(118,163,121,0.12); color: var(--sage); }
  .verdict-dont { background: rgba(184,135,148,0.12); color: var(--pink); }

  /* ── ILLUSTRATION ── */
  .illustration-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; margin-bottom: 2rem; }
  .illustration-card {
    border-radius: 10px; border: 1px solid var(--cream2); overflow: hidden;
    background: var(--white); transition: transform 0.2s, box-shadow 0.2s;
  }
  .illustration-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(37,56,48,0.08); }
  .illustration-preview {
    height: 160px; display: flex; align-items: center; justify-content: center;
    font-size: 3rem; position: relative;
  }
  .illustration-meta { padding: 1rem 1.25rem; }
  .illustration-name { font-weight: 600; font-size: 0.85rem; color: var(--forest); margin-bottom: 3px; }
  .illustration-rule { font-family: 'DM Mono', monospace; font-size: 0.62rem; letter-spacing: 1px; text-transform: uppercase; color: var(--sage2); }
  .illus-do-dont { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem; }

  /* ── ICONOGRAPHY ── */
  .icon-showcase {
    background: var(--white); border-radius: 12px; border: 1px solid var(--cream2);
    padding: 2.5rem; margin-bottom: 2rem;
  }
  .icon-row { display: flex; gap: 1.5rem; flex-wrap: wrap; align-items: center; }
  .icon-item {
    display: flex; flex-direction: column; align-items: center; gap: 0.5rem;
    padding: 1.25rem; border-radius: 8px; background: var(--cream); min-width: 72px;
    transition: background 0.2s;
  }
  .icon-item:hover { background: var(--cream2); }
  .icon-item i { font-size: 1.4rem; color: var(--forest); }
  .icon-item-label { font-family: 'DM Mono', monospace; font-size: 0.55rem; letter-spacing: 1px; text-transform: uppercase; color: var(--sage2); }
  .icon-rule-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; margin-bottom: 2rem; }
  .icon-rule-card { background: var(--white); border-radius: 10px; border: 1px solid var(--cream2); padding: 1.75rem; }
  .icon-rule-icon { width: 40px; height: 40px; border-radius: 8px; background: var(--cream); display: flex; align-items: center; justify-content: center; font-size: 1.1rem; color: var(--sage); margin-bottom: 1rem; }
  .icon-rule-title { font-weight: 600; font-size: 0.875rem; color: var(--forest); margin-bottom: 0.5rem; }
  .icon-rule-body { font-size: 0.82rem; color: var(--sage2); line-height: 1.65; }

  /* ── PHOTOGRAPHY ── */
  .photo-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem; }
  .photo-card {
    border-radius: 12px; overflow: hidden; border: 1px solid var(--cream2);
    background: var(--white); transition: transform 0.2s, box-shadow 0.2s;
  }
  .photo-card:hover { transform: translateY(-3px); box-shadow: 0 10px 30px rgba(37,56,48,0.1); }
  .photo-mock {
    height: 200px; display: flex; align-items: center; justify-content: center;
    position: relative; overflow: hidden;
  }
  .photo-mock-label {
    position: absolute; top: 12px; left: 12px;
    font-family: 'DM Mono', monospace; font-size: 0.58rem; letter-spacing: 2px;
    text-transform: uppercase; padding: 4px 10px; border-radius: 20px;
  }
  .photo-meta { padding: 1.25rem; }
  .photo-title { font-weight: 600; font-size: 0.875rem; color: var(--forest); margin-bottom: 4px; }
  .photo-desc { font-size: 0.82rem; color: var(--sage2); line-height: 1.65; }
  .photo-rules-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; }

  /* ── SHOWCASE ── */
  .showcase-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin-bottom: 2rem; }
  .showcase-card {
    border-radius: 12px; overflow: hidden; border: 1px solid var(--cream2);
    background: var(--white); transition: transform 0.2s, box-shadow 0.2s;
  }
  .showcase-card:hover { transform: translateY(-3px); box-shadow: 0 10px 30px rgba(37,56,48,0.1); }
  .showcase-mock { position: relative; overflow: hidden; }
  .showcase-meta { padding: 1.25rem; }
  .showcase-tag {
    font-family: 'DM Mono', monospace; font-size: 0.58rem; letter-spacing: 2px;
    text-transform: uppercase; padding: 3px 10px; border-radius: 20px;
    background: var(--cream); color: var(--sage2); display: inline-block; margin-bottom: 0.5rem;
  }
  .showcase-title { font-weight: 600; font-size: 0.875rem; color: var(--forest); margin-bottom: 4px; }
  .showcase-desc { font-size: 0.8rem; color: var(--sage2); line-height: 1.65; }
  .perception-block {
    background: var(--forest); border-radius: 12px; padding: 3.5rem; margin-bottom: 2rem;
    position: relative; overflow: hidden;
  }
  .perception-block::before {
    content: ''; position: absolute; top: -80px; right: -80px;
    width: 280px; height: 280px;
    background: radial-gradient(circle, rgba(210,169,116,0.08) 0%, transparent 65%);
    border-radius: 50%;
  }
  .perception-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2rem; margin-top: 2rem; }
  .perception-item { text-align: center; }
  .perception-quote {
    font-family: 'Bebas Neue', sans-serif; font-size: 1.2rem; letter-spacing: 0.5px;
    color: var(--cream); margin-bottom: 0.5rem; line-height: 1.1;
  }
  .perception-source { font-family: 'DM Mono', monospace; font-size: 0.6rem; letter-spacing: 2px; text-transform: uppercase; color: var(--sage); }

  /* ── RESPONSIVE ── */
  @media (max-width: 991px) {
    .brand-sidebar { display: none; }
    .main-content { margin-left: 0; }
    .brand-section { padding: 3rem 2rem; }
    .brand-hero { padding: 3.5rem 2rem; min-height: auto; }
    .type-scale-grid, .type-pair-block, .overview-grid { grid-template-columns: 1fr; }
    .hero-meta-row { flex-wrap: wrap; gap: 1.5rem; }
    .logo-variants-grid { grid-template-columns: 1fr; }
    .dos-donts-grid { grid-template-columns: 1fr; }
    .components-grid { grid-template-columns: 1fr; }
    .story-split, .voice-grid, .type-rules-grid, .type-do-dont, .illus-do-dont,
    .photo-grid, .showcase-grid, .values-grid, .icon-rule-grid, .illustration-grid,
    .photo-rules-grid, .perception-grid, .sizing-grid { grid-template-columns: 1fr; }
  }
</style>
</head>
