    <div class="icon-showcase">
      <div style="font-family:'DM Mono',monospace;font-size:0.6rem;letter-spacing:3px;text-transform:uppercase;color:var(--sage2);margin-bottom:1.25rem;">Approved Icon Style — Line Icons at 1.5px stroke</div>
