        <div class="icon-item"><i class="bi bi-lock"></i><span class="icon-item-label">Secure</span></div>
        <div class="icon-item"><i class="bi bi-diagram-3"></i><span class="icon-item-label">Workflow</span></div>
        <div class="icon-item"><i class="bi bi-bar-chart-line"></i><span class="icon-item-label">Analytics</span></div>
        <div class="icon-item"><i class="bi bi-cloud-check"></i><span class="icon-item-label">Cloud</span></div>
