<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/js/bootstrap.bundle.min.js"></script>
<script>
  const sections = Array.from(document.querySelectorAll('.section-anchor[id]'));
  const navLinks = Array.from(document.querySelectorAll('.sidebar-nav a[href^="#"]'));
  const linkById = new Map(
    navLinks.map(link => [link.getAttribute('href').slice(1), link])
  );

  function setActiveLinkById(id) {
    navLinks.forEach(link => link.classList.remove('active'));
    const activeLink = linkById.get(id);
    if (activeLink) activeLink.classList.add('active');
  }

  function getActiveSectionId() {
    if (!sections.length) return null;

    const activationLine = window.scrollY + (window.innerHeight * 0.35);
    let currentSection = sections[0];

    for (const section of sections) {
      if (section.offsetTop <= activationLine) {
        currentSection = section;
      } else {
        break;
      }
    }

    return currentSection.id || null;
  }

  let rafId = null;
  function syncActiveNavOnScroll() {
    if (rafId !== null) return;
    rafId = window.requestAnimationFrame(() => {
      const activeId = getActiveSectionId();
      if (activeId) setActiveLinkById(activeId);
      rafId = null;
    });
  }

  navLinks.forEach(link => {
    link.addEventListener('click', () => {
      const targetId = link.getAttribute('href').slice(1);
      setActiveLinkById(targetId);
    });
  });

  window.addEventListener('scroll', syncActiveNavOnScroll, { passive: true });
  window.addEventListener('resize', syncActiveNavOnScroll);
  window.addEventListener('hashchange', syncActiveNavOnScroll);
  window.addEventListener('load', syncActiveNavOnScroll);

  // Initial state on first paint.
  syncActiveNavOnScroll();
</script>
